/*
  Hui Chat Socket.IO browser client bootstrap.

  This project needs the Socket.IO browser client before the chat modules run.
  Older packages shipped this file as a text placeholder, which made window.io
  undefined and caused the whole front-end boot chain to fail. This loader keeps
  the local script path stable and pulls the official browser bundle when the
  real local bundle has not been installed yet.
*/
(function () {
  try {
    if (typeof window === "undefined" || typeof document === "undefined") return;
    if (typeof window.io === "function") return;

    var src = "https://cdn.socket.io/4.5.0/socket.io.min.js";
    window.HUI_SOCKETIO_CLIENT_FALLBACK_SRC = src;

    if (document.readyState === "loading" && typeof document.write === "function") {
      document.write('<script src="' + src + '"><\/script>');
      return;
    }

    var script = document.createElement("script");
    script.src = src;
    script.async = false;
    (document.head || document.documentElement).appendChild(script);
  } catch (e) {
    try { window.HUI_SOCKETIO_CLIENT_MISSING = true; } catch (_) {}
  }
})();
